package com.xwc.open.easybatis.core.support.table;import lombok.Data;import java.lang.reflect.Field;import java.lang.reflect.Method;import java.util.Map;/** * 创建人：徐卫超 * 时间：2019/8/3 16:35 * 功能：对象的属性描述 */@Datapublic class Column {    /**     * 是否需要进行result映射     */    private boolean result;    /**     * 属性的名字     */    private String field;    /**     * 属性的getter 方法     */    private Method getter;    /**     * 属性的setter 方法     */    private Method setter;    /**     * 和数据库的对应关系     */    private String column;    /**     * 查询忽略     */    private boolean selectIgnore;    /**     * 更新忽略     */    private boolean updateIgnore;    /**     * 插入忽略     */    private boolean insertIgnore;    private Field source;    public Column(String field, Method getter, Method setter, String column,                  boolean selectIgnore, boolean updateIgnore, boolean insertIgnore) {        this.field = field;        this.getter = getter;        this.setter = setter;        this.column = column;        this.selectIgnore = selectIgnore;        this.updateIgnore = updateIgnore;        this.insertIgnore = insertIgnore;    }    public Column(Map<String, Object> map, Method getter, Method setter, String field) {        this.field = field;        this.setter = setter;        this.getter = getter;        this.updateIgnore = map.get("updateIgnore") != null && (boolean) map.get("updateIgnore");        this.selectIgnore = map.get("selectIgnore") != null && (boolean) map.get("selectIgnore");        this.insertIgnore = map.get("insertIgnore") != null && (boolean) map.get("insertIgnore");        this.column = String.valueOf(map.get("column") == null ? "" : map.get("column"));    }    public Column(Column mate) {        this.field = mate.field;        this.getter = mate.getter;        this.setter = mate.setter;        this.column = mate.column;        this.selectIgnore = mate.selectIgnore;        this.updateIgnore = mate.updateIgnore;        this.result = mate.result;    }}